const raw = $input.first().json.output || $input.first().json.text || "";

let clean = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();

const start = clean.indexOf("{");
const end = clean.lastIndexOf("}");

if (start === -1 || end === -1) {
  throw new Error("No JSON found in agent output");
}

clean = clean.substring(start, end + 1);
clean = clean.replace(/[\x00-\x1F\x7F]/g, " ").replace(/  +/g, " ");

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  const keys = ["primary_keywords", "secondary_keywords", "long_tail_keywords", "geo_blocks", "evidence_anchors", "perplexity_facts", "faq_pairs", "draft_snippet", "wp_category_id"];
  parsed = {};

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const nextKey = keys[i + 1];

    let pattern;
    if (nextKey) {
      pattern = new RegExp(`"${key}"\\s*:\\s*"([\\s\\S]*?)"\\s*,\\s*"${nextKey}"`, "i");
    } else {
      pattern = new RegExp(`"${key}"\\s*:\\s*"([\\s\\S]*?)"\\s*}`, "i");
    }

    const match = clean.match(pattern);
    parsed[key] = match ? match[1].replace(/"/g, "«»").trim() : "";
  }
}

const required = ["primary_keywords", "secondary_keywords", "long_tail_keywords", "geo_blocks", "evidence_anchors", "perplexity_facts", "faq_pairs", "draft_snippet", "wp_category_id"];
for (const key of required) {
  if (!parsed[key]) parsed[key] = "";
}

if (!parsed["wp_category_id"]) parsed["wp_category_id"] = "2";

return [{ json: parsed }];
